let historyTableInitialized=!1;function initializeHistoryTable(){if(historyTableInitialized)return;if($.fn.DataTable.isDataTable("#carHistoryTable")){historyTableInitialized=!0;return}let i=null;if(window.carDetailsConfig&&window.carDetailsConfig.carId?i=window.carDetailsConfig.carId:$("#car_id").length&&$("#car_id").val()?i=$("#car_id").val():$('input[name="car_id"]').length&&$('input[name="car_id"]').first().val()&&(i=$('input[name="car_id"]').first().val()),!i){console.error("Car ID not provided for history table");return}historyTableInitialized=!0;try{$("#carHistoryTable").DataTable({responsive:!0,order:[[1,"desc"]],language:{emptyTable:"No history"},ajax:{url:"actions/history.php",dataSrc:"history",type:"POST",data:function(r){r.csrf=window.carDetailsConfig?.csrf,r.car_id=i}},columns:[{data:"operation",responsivePriority:1},{data:"mtime",responsivePriority:1},{data:"year",responsivePriority:2},{data:"type",responsivePriority:2},{data:"chassis",responsivePriority:1},{data:"series",responsivePriority:3},{data:"variant",responsivePriority:3},{data:"color",responsivePriority:3},{data:"engine",responsivePriority:3},{data:"purchasedate",responsivePriority:3},{data:"solddate",responsivePriority:3},{data:"comments",responsivePriority:3},{data:"image",searchable:!1,responsivePriority:3,render:function(r,t,a){return r?carousel(a,a.car_id):""}},{data:"fname",responsivePriority:3},{data:"city",responsivePriority:3},{data:"state",responsivePriority:3},{data:"country",responsivePriority:3}]}).on("draw.dt",function(){typeof highlightDifferences=="function"&&highlightDifferences()})}catch(e){throw console.error("Failed to initialize DataTable:",e),historyTableInitialized=!1,e}}$(document).ready(function(){initializeHistoryTable()});
